import { Component } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { Router } from '@angular/router';
import { AuthService } from '../../../services/auth.service';

@Component({
  selector: 'app-register',
  templateUrl: './register.component.html'
})
export class RegisterComponent {
  registerForm: FormGroup;
  errorMessage: string = '';
  successMessage: string = '';

  constructor(
    private fb: FormBuilder,
    private authService: AuthService,
    private router: Router
  ) {
    this.registerForm = this.fb.group({
      nombre: ['', Validators.required],
      email: ['', [Validators.required, Validators.email]],
      // El backend exige mínimo 6 caracteres, así que validamos eso también en el Frontend
      password: ['', [Validators.required, Validators.minLength(6)]]
    });
  }

  onSubmit() {
    if (this.registerForm.invalid) return;

    this.errorMessage = '';
    this.successMessage = '';

    this.authService.register(this.registerForm.value).subscribe({
      next: () => {
        // Le mostramos un mensaje de éxito al usuario antes de mandarlo al login
        this.successMessage = 'Usuario registrado exitosamente. Ahora puedes iniciar sesión.';
        this.registerForm.reset(); // Limpiamos el formulario
      },
      error: (err) => {
        this.errorMessage = err.error?.mensaje || 'Ocurrió un error al registrar el usuario.';
      }
    });
  }
}
<div class="container mt-5">
  <div class="row justify-content-center">
    <div class="col-md-6">
      <div class="card shadow-sm">
        <div class="card-body">
          <h2 class="card-title text-center mb-4">Registro de Usuario</h2>

          <div *ngIf="errorMessage" class="alert alert-danger">{{ errorMessage }}</div>
          <div *ngIf="successMessage" class="alert alert-success">{{ successMessage }}</div>

          <form [formGroup]="registerForm" (ngSubmit)="onSubmit()">

            <div class="mb-3">
              <label class="form-label">Nombre Completo</label>
              <input type="text" class="form-control" formControlName="nombre" placeholder="Juan Perez">
              <div *ngIf="registerForm.get('nombre')?.invalid && registerForm.get('nombre')?.touched" class="text-danger small mt-1">
                El nombre es obligatorio.
              </div>
            </div>

            <div class="mb-3">
              <label class="form-label">Correo Electrónico</label>
              <input type="email" class="form-control" formControlName="email" placeholder="tu@email.com">
              <div *ngIf="registerForm.get('email')?.invalid && registerForm.get('email')?.touched" class="text-danger small mt-1">
                Ingresa un correo válido.
              </div>
            </div>

            <div class="mb-3">
              <label class="form-label">Contraseña</label>
              <input type="password" class="form-control" formControlName="password" placeholder="Min. 6 caracteres">
              <div *ngIf="registerForm.get('password')?.invalid && registerForm.get('password')?.touched" class="text-danger small mt-1">
                La contraseña debe tener al menos 6 caracteres.
              </div>
            </div>

            <div class="d-grid gap-2">
              <button type="submit" class="btn btn-success" [disabled]="registerForm.invalid">Registrarse</button>
            </div>

            <div class="text-center mt-3">
              ¿Ya tienes cuenta? <a routerLink="/login">Inicia sesión</a>
            </div>

          </form>
        </div>
      </div>
    </div>
  </div>
</div>
